{
  "name": "TradeMind AI",
  "description": "An advanced AI trading assistant that analyzes charts, balance sheets, and market news to provide buy/sell advice using deep reasoning and real-time search grounding."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MarketNewsItem {
  title: string;
  source: string;
  url: string;
  sentiment: 'positive' | 'negative' | 'neutral';
  snippet: string;
}

export interface TradeAnalysis {
  recommendation: 'BUY' | 'SELL' | 'HOLD';
  confidenceScore: number; // 0-100
  summary: string;
  reasoning: string[];
  riskFactors: string[];
  keyMetrics: { label: string; value: string; trend: 'up' | 'down' | 'neutral' }[];
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  MARKET_PULSE = 'MARKET_PULSE',
  CHAT = 'CHAT',
}

import { GoogleGenAI, Type } from "@google/genai";
import { MarketNewsItem, TradeAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// 1. Search Grounding (Market Pulse) - Uses gemini-3-flash-preview
export const fetchMarketNews = async (ticker: string): Promise<MarketNewsItem[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Find the latest financial news, earnings reports, and market sentiment for ${ticker}. 
      Return a list of 3-5 key news items with their sentiment.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              source: { type: Type.STRING },
              url: { type: Type.STRING },
              sentiment: { type: Type.STRING, enum: ['positive', 'negative', 'neutral'] },
              snippet: { type: Type.STRING },
            },
            required: ['title', 'source', 'sentiment', 'snippet'],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];

    // We also need to extract grounding chunks if available to ensure we have valid URLs
    // logic mainly relies on the JSON output but good to keep in mind for generic text responses.

    return JSON.parse(text) as MarketNewsItem[];
  } catch (error) {
    console.error("Error fetching market news:", error);
    return [];
  }
};

// 2. Deep Analysis (Thinking Mode) - Uses gemini-3-pro-preview
export const analyzeTrade = async (
  ticker: string,
  context: string,
  images: string[] // base64 strings
): Promise<TradeAnalysis> => {
  const parts: any[] = [];

  // Add images
  images.forEach(img => {
    parts.push({
      inlineData: {
        mimeType: 'image/png', // Assuming PNG for simplicity in this demo, usually should detect
        data: img
      }
    });
  });

  // Add prompt
  parts.push({
    text: `You are a senior financial analyst. Conduct a deep, comprehensive analysis on ${ticker}.

    Context provided by user: "${context}"

    Analyze the provided charts (if any), the user notes, and your internal knowledge of the company's financials, balance sheets, and recent performance.

    Thinking Process:
    1. Analyze technical indicators from charts (RSI, MACD, Support/Resistance).
    2. Analyze fundamental data (P/E, EPS, Revenue growth).
    3. Consider macro-economic factors.
    4. Weigh risks vs rewards.

    Output a structured JSON response with your final recommendation.`
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      thinkingConfig: { thinkingBudget: 32768 }, // High budget for deep analysis
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          recommendation: { type: Type.STRING, enum: ['BUY', 'SELL', 'HOLD'] },
          confidenceScore: { type: Type.NUMBER, description: "0 to 100" },
          summary: { type: Type.STRING },
          reasoning: { type: Type.ARRAY, items: { type: Type.STRING } },
          riskFactors: { type: Type.ARRAY, items: { type: Type.STRING } },
          keyMetrics: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                value: { type: Type.STRING },
                trend: { type: Type.STRING, enum: ['up', 'down', 'neutral'] }
              }
            }
          }
        },
        required: ['recommendation', 'confidenceScore', 'summary', 'reasoning', 'riskFactors']
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No analysis generated");
  return JSON.parse(text) as TradeAnalysis;
};

// 3. Fast Response (Quick Lookup) - Uses gemini-2.5-flash-lite-latest (or flash-lite)
// Note: Prompt says "gemini-2.5-flash-lite".
export const quickLookup = async (term: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-flash-lite-latest',
    contents: `Explain the financial term or concept "${term}" briefly in one sentence.`,
  });
  return response.text || "Could not define term.";
};

// 4. Chatbot - Uses gemini-3-pro-preview
// Note: We create a new chat instance usually, but for stateless REST calls we can just append history.
// For this demo, we'll implement a simple history-based call.
export const sendChatMessage = async (history: {role: string, parts: {text: string}[]}[], newMessage: string) => {
    const chat = ai.chats.create({
        model: 'gemini-3-pro-preview',
        history: history,
        config: {
            systemInstruction: "You are a helpful and cautious financial assistant. Do not give binding financial advice, but provide educational analysis.",
        }
    });

    const response = await chat.sendMessage({ message: newMessage });
    return response.text;
}

import React, { useState, useRef } from 'react';
import { analyzeTrade } from '../services/geminiService';
import { TradeAnalysis } from '../types';
import { Icons } from './ui/Icons';

export const Dashboard: React.FC = () => {
  const [ticker, setTicker] = useState('');
  const [context, setContext] = useState('');
  const [images, setImages] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<TradeAnalysis | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        // Remove data URL prefix for Gemini API if needed, 
        // strictly speaking google-genai handles generic blobs but keeping it clean:
        // extracting base64 part:
        const base64Content = base64String.split(',')[1];
        setImages(prev => [...prev, base64Content]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!ticker) return;
    setIsLoading(true);
    setResult(null);
    try {
      const data = await analyzeTrade(ticker, context, images);
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      {/* Input Section */}
      <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-xl">
        <h2 className="text-2xl font-bold mb-4 flex items-center gap-2">
          <Icons.BrainCircuit className="text-purple-400" />
          <span className="bg-gradient-to-r from-purple-400 to-blue-400 bg-clip-text text-transparent">
            Deep Trade Analysis
          </span>
        </h2>
        <p className="text-slate-400 mb-6 text-sm">
          Powered by Gemini 3 Pro with Thinking Mode. Upload charts or balance sheets for deeper context.
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-1">Asset Ticker</label>
              <input
                type="text"
                value={ticker}
                onChange={(e) => setTicker(e.target.value.toUpperCase())}
                placeholder="e.g. AAPL, BTC, NVDA"
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-1">Context / Notes</label>
              <textarea
                value={context}
                onChange={(e) => setContext(e.target.value)}
                placeholder="E.g. I'm worried about the upcoming earnings call..."
                className="w-full h-32 bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-purple-500 outline-none resize-none"
              />
            </div>
          </div>

          <div className="space-y-4">
             <label className="block text-sm font-medium text-slate-300 mb-1">Chart / Balance Sheet</label>
             <div 
                onClick={() => fileInputRef.current?.click()}
                className="border-2 border-dashed border-slate-700 rounded-lg h-48 flex flex-col items-center justify-center cursor-pointer hover:border-purple-500 hover:bg-slate-800/50 transition-all group"
             >
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*"
                  onChange={handleImageUpload}
                />
                <Icons.Upload className="w-8 h-8 text-slate-500 group-hover:text-purple-400 mb-2" />
                <span className="text-sm text-slate-500 group-hover:text-slate-300">
                  Click to upload image
                </span>
                {images.length > 0 && (
                  <span className="mt-2 text-xs text-green-400 bg-green-900/30 px-2 py-1 rounded-full">
                    {images.length} image(s) attached
                  </span>
                )}
             </div>
          </div>
        </div>

        <div className="mt-6 flex justify-end">
          <button
            onClick={handleAnalyze}
            disabled={isLoading || !ticker}
            className={`
              flex items-center gap-2 px-6 py-3 rounded-lg font-semibold text-white transition-all
              ${isLoading || !ticker 
                ? 'bg-slate-700 cursor-not-allowed text-slate-400' 
                : 'bg-purple-600 hover:bg-purple-500 shadow-lg shadow-purple-900/20 active:scale-95'}
            `}
          >
            {isLoading ? (
              <>
                <Icons.Loader2 className="animate-spin" />
                Thinking deeply...
              </>
            ) : (
              <>
                <Icons.Zap />
                Generate Advice
              </>
            )}
          </button>
        </div>
      </div>

      {/* Results Section */}
      {result && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-fade-in">
          {/* Gauge / Score */}
          <div className="md:col-span-1 bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-xl flex flex-col items-center justify-center text-center">
             <div className="text-sm text-slate-400 uppercase tracking-wider mb-2">Recommendation</div>
             <div className={`text-4xl font-black mb-2 ${
               result.recommendation === 'BUY' ? 'text-green-400' : 
               result.recommendation === 'SELL' ? 'text-red-400' : 'text-yellow-400'
             }`}>
               {result.recommendation}
             </div>
             <div className="w-full bg-slate-700 h-2 rounded-full mb-2 overflow-hidden">
                <div 
                  className={`h-full transition-all duration-1000 ${
                    result.recommendation === 'BUY' ? 'bg-green-500' : 
                    result.recommendation === 'SELL' ? 'bg-red-500' : 'bg-yellow-500'
                  }`}
                  style={{ width: `${result.confidenceScore}%` }}
                />
             </div>
             <div className="text-xs text-slate-500">Confidence: {result.confidenceScore}%</div>
          </div>

          {/* Reasoning */}
          <div className="md:col-span-2 bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-xl">
            <h3 className="text-lg font-semibold text-white mb-3">AI Reasoning</h3>
            <p className="text-slate-300 text-sm mb-4 leading-relaxed">{result.summary}</p>
            <div className="space-y-2">
              {result.reasoning.map((reason, idx) => (
                <div key={idx} className="flex items-start gap-2 text-sm text-slate-300">
                  <Icons.CheckCircle className="w-4 h-4 text-purple-400 mt-0.5 shrink-0" />
                  <span>{reason}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Metrics & Risks */}
          <div className="md:col-span-3 grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
               <h3 className="text-lg font-semibold text-white mb-4">Key Metrics</h3>
               <div className="grid grid-cols-2 gap-4">
                  {result.keyMetrics?.map((metric, i) => (
                    <div key={i} className="bg-slate-900 p-3 rounded-lg border border-slate-700">
                      <div className="text-xs text-slate-400">{metric.label}</div>
                      <div className="flex items-center gap-2 mt-1">
                        <span className="text-lg font-medium text-white">{metric.value}</span>
                        {metric.trend === 'up' && <Icons.TrendingUp className="w-4 h-4 text-green-500" />}
                        {metric.trend === 'down' && <Icons.TrendingDown className="w-4 h-4 text-red-500" />}
                        {metric.trend === 'neutral' && <Icons.Minus className="w-4 h-4 text-slate-500" />}
                      </div>
                    </div>
                  ))}
               </div>
            </div>

            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 border-l-4 border-l-yellow-500">
               <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
                 <Icons.AlertTriangle className="text-yellow-500" />
                 Risk Factors
               </h3>
               <ul className="list-disc list-inside space-y-2 text-slate-300 text-sm">
                 {result.riskFactors.map((risk, i) => (
                   <li key={i}>{risk}</li>
                 ))}
               </ul>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { fetchMarketNews } from '../services/geminiService';
import { MarketNewsItem } from '../types';
import { Icons } from './ui/Icons';

export const MarketPulse: React.FC = () => {
  const [query, setQuery] = useState('');
  const [news, setNews] = useState<MarketNewsItem[]>([]);
  const [loading, setLoading] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query) return;
    setLoading(true);
    try {
      const results = await fetchMarketNews(query);
      setNews(results);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-slate-800 p-8 rounded-xl border border-slate-700 shadow-xl mb-8">
        <h2 className="text-2xl font-bold mb-4 flex items-center gap-2">
          <Icons.Search className="text-blue-400" />
          <span className="bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text text-transparent">
            Market Pulse
          </span>
        </h2>
        <p className="text-slate-400 mb-6">
          Real-time market grounding using Google Search. Get the latest sentiment on any asset.
        </p>

        <form onSubmit={handleSearch} className="flex gap-2 mb-8">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search ticker (e.g. TSLA) or market event"
            className="flex-1 bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
          />
          <button 
            type="submit" 
            disabled={loading}
            className="bg-blue-600 hover:bg-blue-500 px-6 rounded-lg text-white font-semibold transition-colors flex items-center gap-2"
          >
            {loading ? <Icons.Loader2 className="animate-spin" /> : <Icons.Search />}
            Search
          </button>
        </form>

        <div className="space-y-4">
          {news.map((item, idx) => (
            <div key={idx} className="bg-slate-900/50 p-4 rounded-lg border border-slate-700/50 hover:border-blue-500/50 transition-colors">
              <div className="flex justify-between items-start mb-2">
                <a href={item.url} target="_blank" rel="noopener noreferrer" className="text-lg font-medium text-blue-300 hover:text-blue-200 hover:underline">
                  {item.title}
                </a>
                <span className={`px-2 py-1 rounded text-xs font-bold uppercase tracking-wider
                  ${item.sentiment === 'positive' ? 'bg-green-900/50 text-green-400' :
                    item.sentiment === 'negative' ? 'bg-red-900/50 text-red-400' :
                    'bg-slate-700 text-slate-300'}
                `}>
                  {item.sentiment}
                </span>
              </div>
              <p className="text-slate-400 text-sm mb-2">{item.snippet}</p>
              <div className="text-xs text-slate-500">Source: {item.source}</div>
            </div>
          ))}
          {!loading && news.length === 0 && (
            <div className="text-center text-slate-500 py-8">
              Enter a ticker above to scan the web for latest financial data.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { sendChatMessage } from '../services/geminiService';
import { ChatMessage } from '../types';
import { Icons } from './ui/Icons';
import ReactMarkdown from 'react-markdown';

export const ChatBot: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'model', text: 'Hello! I am your financial assistant. Ask me anything about trading strategies, terminology, or specific assets.', timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      // Transform internal messages to Gemini history format
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const responseText = await sendChatMessage(history, userMsg.text);

      const botMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: responseText || "I couldn't generate a response.", 
        timestamp: Date.now() 
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = { id: (Date.now() + 1).toString(), role: 'model', text: "Sorry, I encountered an error connecting to the server.", timestamp: Date.now() };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto h-[600px] flex flex-col bg-slate-800 rounded-xl border border-slate-700 shadow-xl overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-slate-700 bg-slate-900/50 flex items-center gap-3">
        <div className="bg-emerald-500/10 p-2 rounded-lg">
          <Icons.MessageSquare className="text-emerald-400 w-5 h-5" />
        </div>
        <div>
          <h3 className="font-semibold text-white">Financial Advisor Chat</h3>
          <p className="text-xs text-slate-400">Powered by Gemini 3 Pro</p>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] rounded-xl p-4 ${
              msg.role === 'user' 
                ? 'bg-blue-600 text-white rounded-br-none' 
                : 'bg-slate-700 text-slate-200 rounded-bl-none'
            }`}>
              <ReactMarkdown className="prose prose-invert prose-sm">
                {msg.text}
              </ReactMarkdown>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-slate-700 rounded-xl rounded-bl-none p-4 flex gap-1">
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-100"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-200"></span>
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <form onSubmit={handleSend} className="p-4 bg-slate-900/50 border-t border-slate-700 flex gap-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask about market trends, strategies..."
          className="flex-1 bg-slate-800 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-emerald-500 transition-colors"
        />
        <button 
          type="submit"
          disabled={!input.trim() || isTyping}
          className="bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg transition-colors"
        >
          <Icons.Zap />
        </button>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { quickLookup } from '../services/geminiService';
import { Icons } from './ui/Icons';

export const QuickLookup: React.FC = () => {
  const [term, setTerm] = useState('');
  const [definition, setDefinition] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLookup = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!term) return;
    setLoading(true);
    setDefinition('');
    try {
      const result = await quickLookup(term);
      setDefinition(result);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-slate-800/50 border border-slate-700 rounded-xl p-4">
      <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-3 flex items-center gap-2">
        <Icons.Zap className="w-4 h-4 text-yellow-400" />
        Quick Define
