import { GoogleGenAI, Type } from "@google/genai";
import { MarketNewsItem, TradeAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// 1. Search Grounding (Market Pulse) - Uses gemini-3-flash-preview
export const fetchMarketNews = async (ticker: string): Promise<MarketNewsItem[]> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Find the latest financial news, earnings reports, and market sentiment for ${ticker}. 
      Return a list of 3-5 key news items with their sentiment.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              source: { type: Type.STRING },
              url: { type: Type.STRING },
              sentiment: { type: Type.STRING, enum: ['positive', 'negative', 'neutral'] },
              snippet: { type: Type.STRING },
            },
            required: ['title', 'source', 'sentiment', 'snippet'],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];

    return JSON.parse(text) as MarketNewsItem[];
  } catch (error) {
    console.error("Error fetching market news:", error);
    return [];
  }
};

// 2. Deep Analysis (Thinking Mode) - Uses gemini-3-pro-preview with Google Search
export const analyzeTrade = async (
  ticker: string,
  context: string,
  images: string[] // base64 strings
): Promise<TradeAnalysis> => {
  const parts: any[] = [];

  // Add images if provided
  if (images && images.length > 0) {
    images.forEach(img => {
      parts.push({
        inlineData: {
          mimeType: 'image/png', 
          data: img
        }
      });
    });
  }

  // Add prompt
  parts.push({
    text: `You are a senior financial analyst. Conduct a deep, comprehensive analysis on ${ticker}.

    User Context: "${context}"

    Task:
    1. If images are provided, analyze them (charts, balance sheets).
    2. REQUIRED: Use the Google Search tool to find the LATEST real-time data for ${ticker}, including:
       - Current stock price and recent price action.
       - Key technical indicators (RSI, MACD, Moving Averages) from reputable financial sites.
       - Latest quarterly earnings reports, revenue growth, and balance sheet summaries (Assets, Liabilities, Cash Flow).
       - Recent news or macro events affecting the stock.

    Thinking Process:
    1. Gather data via Search (or image analysis).
    2. Synthesize technical and fundamental factors.
    3. Weigh risks (market volatility, sector risks) vs rewards.
    4. Formulate a clear recommendation.

    Output a structured JSON response with your final recommendation.`
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      tools: [{ googleSearch: {} }],
      thinkingConfig: { thinkingBudget: 16384 }, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          recommendation: { type: Type.STRING, enum: ['BUY', 'SELL', 'HOLD'] },
          confidenceScore: { type: Type.NUMBER, description: "0 to 100" },
          summary: { type: Type.STRING },
          reasoning: { type: Type.ARRAY, items: { type: Type.STRING } },
          riskFactors: { type: Type.ARRAY, items: { type: Type.STRING } },
          keyMetrics: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                value: { type: Type.STRING },
                trend: { type: Type.STRING, enum: ['up', 'down', 'neutral'] }
              }
            }
          }
        },
        required: ['recommendation', 'confidenceScore', 'summary', 'reasoning', 'riskFactors']
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No analysis generated");
  return JSON.parse(text) as TradeAnalysis;
};

// 3. Fast Response (Quick Lookup) - Uses gemini-2.5-flash-lite-latest (or flash-lite)
export const quickLookup = async (term: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-flash-lite-latest',
    contents: `Explain the financial term or concept "${term}" briefly in one sentence.`,
  });
  return response.text || "Could not define term.";
};

// 4. Chatbot - Uses gemini-3-pro-preview
export const sendChatMessage = async (history: {role: string, parts: {text: string}[]}[], newMessage: string) => {
    const chat = ai.chats.create({
        model: 'gemini-3-pro-preview',
        history: history,
        config: {
            systemInstruction: "You are a helpful and cautious financial assistant. Do not give binding financial advice, but provide educational analysis.",
        }
    });

    const response = await chat.sendMessage({ message: newMessage });
    return response.text;
}

