                        {metric.trend === 'down' && <Icons.TrendingDown className="w-4 h-4 text-red-500" />}
                        {metric.trend === 'neutral' && <Icons.Minus className="w-4 h-4 text-slate-500" />}
                      </div>
                    </div>
                  ))}
               </div>
            </div>

            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 border-l-4 border-l-yellow-500">
               <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
                 <Icons.AlertTriangle className="text-yellow-500" />
                 Risk Factors
